import argparse
import json
import os
import numpy as np
import heapq
from collections import deque
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class DirectionalPlanner:
    def __init__(self, dist_denom=3.6, visited_penalty=0.2, reverse_penalty=0.05,
                 history_penalty=0.65, history_len=8, commit_steps=0):
        self.dist_denom = dist_denom
        self.visited_penalty = visited_penalty
        self.reverse_penalty = reverse_penalty
        self.history_penalty = history_penalty
        self.history_len = history_len
        self.commit_steps = commit_steps
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_target_node = None
        self.history_nodes = deque(maxlen=self.history_len)
        self.commit_target = None
        self.commit_ttl = 0

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        nb_to_node = {}
        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                nb_to_node[idx] = j
                node_to_nb[j] = idx

        # Determine first-step neighbor for each reachable node
        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        dir_scores = [0.0] * len(neighbors)
        has_utility = False
        remaining_steps = 128 - self.step_count

        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            has_utility = True

            d = dist[j]
            score = utility / (d + self.dist_denom)

            if nodes[j].get("visited", False):
                score *= self.visited_penalty

            if j in self.history_nodes:
                score *= self.history_penalty

            # Step budget guard: penalize targets that likely exceed remaining steps
            est_steps = d / 3.2
            if est_steps > remaining_steps:
                score = -1.0

            nb_idx = first_step[j]
            dir_scores[nb_idx] += score

        # Anti-backtracking: penalize reversing the previous move
        if self.prev_target_node is not None:
            prev_node = self.prev_target_node
            if prev_node in node_to_nb:
                rev_nb = node_to_nb[prev_node]
                dir_scores[rev_nb] *= self.reverse_penalty

        # Commitment handling
        if self.commit_target is not None and self.commit_ttl > 0:
            if 0 <= self.commit_target < N:
                if (float(nodes[self.commit_target].get("utility", 0)) > 0 and
                        dist[self.commit_target] < float('inf') and
                        dist[self.commit_target] > 1e-6):
                    cur = self.commit_target
                    depth = 0
                    while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                        cur = prev[cur]
                        depth += 1
                    if prev[cur] == r_idx and cur in node_to_nb:
                        self.commit_ttl -= 1
                        self.prev_target_node = self.commit_target
                        self.history_nodes.append(self.commit_target)
                        return tuple(float(x) for x in neighbors[node_to_nb[cur]])
            self.commit_target = None
            self.commit_ttl = 0

        best_nb = None
        best_score = -1.0

        if has_utility:
            for i, s in enumerate(dir_scores):
                if s > best_score:
                    best_score = s
                    best_nb = i
        else:
            # Fallback 1: nearest frontier
            if frontiers:
                front_arr = np.array(frontiers, dtype=float)
                fd = np.linalg.norm(front_arr - robot_pos, axis=1)
                nearest_frontier = front_arr[np.argmin(fd)]
                best_fn = None
                best_fdist = float('inf')
                for j in range(N):
                    if dist[j] == float('inf'):
                        continue
                    nd = float(np.linalg.norm(
                        np.array(nodes[j]["coords"], dtype=float) - nearest_frontier
                    ))
                    if nd < best_fdist:
                        best_fdist = nd
                        best_fn = j
                if best_fn is not None:
                    cur = best_fn
                    depth = 0
                    while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                        cur = prev[cur]
                        depth += 1
                    if prev[cur] == r_idx and cur in node_to_nb:
                        best_nb = node_to_nb[cur]
            # Fallback 2: nearest unvisited node
            if best_nb is None:
                best_unvis = None
                best_udist = float('inf')
                for j in range(N):
                    if dist[j] == float('inf') or nodes[j].get("visited", False):
                        continue
                    if dist[j] < best_udist:
                        best_udist = dist[j]
                        best_unvis = j
                if best_unvis is not None:
                    cur = best_unvis
                    depth = 0
                    while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                        cur = prev[cur]
                        depth += 1
                    if prev[cur] == r_idx and cur in node_to_nb:
                        best_nb = node_to_nb[cur]
            # Fallback 3: any reachable node (prefer closer)
            if best_nb is None:
                best_any = None
                best_adist = float('inf')
                for j in range(N):
                    if dist[j] == float('inf'):
                        continue
                    if dist[j] < best_adist:
                        best_adist = dist[j]
                        best_any = j
                if best_any is not None:
                    cur = best_any
                    depth = 0
                    while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                        cur = prev[cur]
                        depth += 1
                    if prev[cur] == r_idx and cur in node_to_nb:
                        best_nb = node_to_nb[cur]

        if best_nb is None:
            best_nb = 0

        target_node = nb_to_node.get(best_nb)
        if target_node is not None:
            self.prev_target_node = target_node
            self.history_nodes.append(target_node)
            if self.commit_steps > 0 and has_utility:
                self.commit_target = target_node
                self.commit_ttl = self.commit_steps

        return tuple(float(x) for x in neighbors[best_nb])


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for _ in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def evaluate_on_maps(data_dir, planner, max_maps_per_type=5, seed=42):
    import random
    random.seed(seed)
    maps = []
    for env_type in ["room", "tunnel", "outdoor"]:
        d = os.path.join(data_dir, "maps_train", env_type)
        if not os.path.isdir(d):
            continue
        files = [f for f in os.listdir(d) if f.endswith(".png")]
        random.shuffle(files)
        for f in files[:max_maps_per_type]:
            maps.append((env_type, os.path.join(d, f)))
    results = []
    for env_type, map_path in maps:
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get("success", False) else 0
        distance = metrics.get("travel_distance", 0.0)
        explored = metrics.get("explored_rate", 0.0)
        score = success * (300.0 / distance) if success and distance > 0 else 0.0
        results.append({
            "type": env_type,
            "success": success,
            "distance": distance,
            "explored": explored,
            "score": score
        })
    total = len(results)
    avg_score = sum(r["score"] for r in results) / total if total else 0.0
    avg_explored = sum(r["explored"] for r in results) / total if total else 0.0
    success_rate = sum(r["success"] for r in results) / total if total else 0.0
    dists = [r["distance"] for r in results if r["success"]]
